var plans = $input.all().map(function(i) { return i.json; });
var results = [];
plans.forEach(function(p) {
  var agency = (p.agency || '').trim();
  var naics = (p.naics || '').trim();
  if (!agency) return;
  // Build GovTribe search query for FPDS awards by this agency
  var searchTerms = agency;
  if (naics) searchTerms += ' NAICS ' + naics;
  results.push({
    json: {
      plan_id: p.id,
      opportunity: p.opportunity,
      agency: agency,
      naics: naics,
      contract_value: p.contract_value,
      stage: p.stage,
      existing_competitors: p.known_competitors || '',
      search_query: searchTerms
    }
  });
});
return results.length > 0 ? results : [{ json: { skip: true, reason: 'no_plans_need_enrichment' } }];

var input = $input.first().json;
var planId = $('Build Agency Queries').first().json.plan_id;
var existingComps = $('Build Agency Queries').first().json.existing_competitors || '';

// Extract competitor names from award data
var awards = input.awards || input.data || [];
var competitors = new Map();
if (Array.isArray(awards)) {
  awards.forEach(function(a) {
    var vendor = a.vendor || a.awardee || a.recipient || '';
    if (typeof vendor === 'object') vendor = vendor.name || vendor.legal_name || '';
    vendor = String(vendor).trim();
    if (!vendor) return;
    if (!competitors.has(vendor)) {
      competitors.set(vendor, { name: vendor, award_count: 0, total_value: 0, last_award: null });
    }
    var c = competitors.get(vendor);
    c.award_count++;
    c.total_value += parseFloat(a.value || a.amount || 0) || 0;
    if (a.date || a.award_date) c.last_award = a.date || a.award_date;
  });
}

var compList = Array.from(competitors.values()).sort(function(a, b) { return b.total_value - a.total_value; }).slice(0, 10);
var compNames = compList.map(function(c) { return c.name; });

// Merge with existing competitors
var allComps = new Set();
if (existingComps) existingComps.split(',').forEach(function(c) { allComps.add(c.trim()); });
compNames.forEach(function(c) { allComps.add(c); });

var landscape = {
  fpds_competitors: compList,
  merged_competitors: Array.from(allComps).join(', '),
  total_awards_analyzed: awards.length,
  fpds_last_enriched: new Date().toISOString().split('T')[0]
};

return [{ json: { plan_id: planId, landscape: landscape, update_sql: "UPDATE gda_capture_plans SET plan_data = plan_data || '" + JSON.stringify(landscape).replace(/'/g, "''") + "'::jsonb WHERE id = " + planId } }];
